from flask import Flask, request
from web3 import Web3, Account, HTTPProvider, eth

app = Flask(__name__)
w3 = Web3(HTTPProvider('https://mainnet.infura.io/v3/{your_infura_project_id}'))

@app.route('/verify_signature', methods=['POST'])
def verify_signature():
    data = request.get_json()
    signature = data.get('signature')
    message = data.get('message')

    try:
        address = w3.eth.account.recoverHash(message_hash=message, signature=signature)
        return {'authenticated': True, 'address': address}
    except ValueError:
        return {'authenticated': False}

if __name__ == '__main__':
    app.run()